checker_dsl:
EXISTS (`method_call_MC`) {
  AND {
    (`the method called by MC is a method named "finalize" with zero parameters`),
    NOT {
      EXISTS (`callable_CALLER`, `finalize_method_FM`) {
        (`CALLER is the method containing the method call MC, FM is a method named "finalize" with zero parameters, CALLER is a method that overrides FM, and the qualifier of MC is a SuperAccess (i.e., "super")`)
      }
    }
  }
}
